+            .parse_cell_pointers(page_bytes, page_size, reserved_per_page)
+            .map_err(|err| FrankenError::DatabaseCorrupt {
+                detail: format!("{owner}: page {} cell pointers invalid: {err}", page_no.get()),
+            })?;
